function CollectionGrid({ collections }) {
  const { div, span, h3, img } = tags;

  return div({ class: css('_grid _gc3 _gap6 _p4') },
    ...collections.map(col =>
      Card({},
        img({ src: col.cover, alt: col.title, class: css('_wfull _h[180px] _object[cover]') }),
        Card.Body({ class: css('_flex _col _gap2') },
          div({ class: css('_flex _aic _jcsb') },
            h3({ class: css('_heading5') }, col.title),
            Badge({ variant: col.isPublic ? 'success' : 'default' }, col.isPublic ? 'Public' : 'Private')
          ),
          span({ class: css('_caption _fgmuted _lineClamp2') }, col.description),
          span({ class: css('_textsm _fgmuted') }, icon('book-open'), ` ${col.itemCount} items`)
        )
      )
    )
  );
}

